# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, Set, List
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]  # item_id -> quantity
    connected: bool = False

class MMOGameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.trade_offers: Dict[str, Dict] = {}
        self.lock = asyncio.Lock()

    async def register_player(self, player_id: str, username: str):
        self.players[player_id] = Player(player_id, username, {})
        print(f"Player {username} registered")

    async def connect_player(self, player_id: str, websocket):
        self.connections[player_id] = websocket
        self.players[player_id].connected = True
        await self.send_player_data(player_id)
        print(f"Player {self.players[player_id].username} connected")

    async def disconnect_player(self, player_id: str):
        if player_id in self.connections:
            del self.connections[player_id]
        self.players[player_id].connected = False
        print(f"Player {self.players[player_id].username} disconnected")

    async def send_player_data(self, player_id: str):
        if player_id in self.connections:
            player = self.players[player_id]
            data = {
                "type": "player_data",
                "player_id": player_id,
                "username": player.username,
                "inventory": player.inventory
            }
            await self.connections[player_id].send(json.dumps(data))

    async def create_item(self, item_id: str, name: str, item_type: str, value: int, owner_id: str):
        item = Item(item_id, name, item_type, value, owner_id)
        self.items[item_id] = item
        self.players[owner_id].inventory[item_id] = self.players[owner_id].inventory.get(item_id, 0) + 1
        print(f"Item {name} created and assigned to {self.players[owner_id].username}")

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int = 1):
        async with self.lock:
            if from_player_id not in self.players or to_player_id not in self.players:
                return False
            
            if item_id not in self.players[from_player_id].inventory or self.players[from_player_id].inventory[item_id] < quantity:
                return False
            
            # Update inventories
            self.players[from_player_id].inventory[item_id] -= quantity
            if self.players[from_player_id].inventory[item_id] <= 0:
                del self.players[from_player_id].inventory[item_id]
            
            self.players[to_player_id].inventory[item_id] = self.players[to_player_id].inventory.get(item_id, 0) + quantity
            
            # Update item ownership if it's a unique item
            if item_id in self.items:
                self.items[item_id].owner_id = to_player_id
            
            # Notify both players
            await self.notify_player_update(from_player_id)
            await self.notify_player_update(to_player_id)
            
            return True

    async def notify_player_update(self, player_id: str):
        if player_id in self.connections and self.players[player_id].connected:
            data = {
                "type": "inventory_update",
                "inventory": self.players[player_id].inventory
            }
            await self.connections[player_id].send(json.dumps(data))

    async def handle_trade_request(self, player_id: str, target_player_id: str, item_id: str, item_quantity: int, offer_item_id: str, offer_quantity: int):
        async with self.lock:
            if player_id not in self.players or target_player_id not in self.players:
                return False
            
            if item_id not in self.players[player_id].inventory or self.players[player_id].inventory[item_id] < item_quantity:
                return False
            
            if offer_item_id not in self.players[target_player_id].inventory or self.players[target_player_id].inventory[offer_item_id] < offer_quantity:
                return False
            
            offer_id = str(uuid.uuid4())
            self.trade_offers[offer_id] = {
                "from_player": player_id,
                "to_player": target_player_id,
                "item_id": item_id,
                "item_quantity": item_quantity,
                "offer_item_id": offer_item_id,
                "offer_quantity": offer_quantity,
                "timestamp": datetime.now().isoformat()
            }
            
            # Notify both players
            await self.send_trade_offer(player_id, offer_id)
            await self.send_trade_offer(target_player_id, offer_id)
            
            return True

    async def send_trade_offer(self, player_id: str, offer_id: str):
        if player_id in self.connections and self.players[player_id].connected:
            offer = self.trade_offers[offer_id]
            data = {
                "type": "trade_offer",
                "offer_id": offer_id,
                "from_player": offer["from_player"],
                "item_id": offer["item_id"],
                "item_quantity": offer["item_quantity"],
                "offer_item_id": offer["offer_item_id"],
                "offer_quantity": offer["offer_quantity"]
            }
            await self.connections[player_id].send(json.dumps(data))

    async def accept_trade(self, player_id: str, offer_id: str):
        async with self.lock:
            if offer_id not in self.trade_offers:
                return False
            
            offer = self.trade_offers[offer_id]
            
            if player_id != offer["to_player"]:
                return False
            
            # Perform the trade
            success = await self.transfer_item(offer["from_player"], offer["to_player"], offer["item_id"], offer["item_quantity"])
            if success:
                success = await self.transfer_item(offer["to_player"], offer["from_player"], offer["offer_item_id"], offer["offer_quantity"])
            
            if success:
                del self.trade_offers[offer_id]
                # Notify both players of success
                await self.notify_player_update(offer["from_player"])
                await self.notify_player_update(offer["to_player"])
            
            return success

    async def handle_message(self, websocket, message: str):
        try:
            data = json.loads(message)
            msg_type = data.get("type")
            player_id = data.get("player_id")
            
            if msg_type == "register":
                await self.register_player(data["player_id"], data["username"])
                await self.connect_player(player_id, websocket)
                
            elif msg_type == "connect":
                await self.connect_player(player_id, websocket)
                
            elif msg_type == "disconnect":
                await self.disconnect_player(player_id)
                
            elif msg_type == "transfer_item":
                await self.transfer_item(
                    player_id, 
                    data["to_player_id"], 
                    data["item_id"], 
                    data.get("quantity", 1)
                )
                
            elif msg_type == "trade_request":
                await self.handle_trade_request(
                    player_id,
                    data["target_player_id"],
                    data["item_id"],
                    data["item_quantity"],
                    data["offer_item_id"],
                    data["offer_quantity"]
                )
                
            elif msg_type == "accept_trade":
                await self.accept_trade(player_id, data["offer_id"])
                
        except Exception as e:
            print(f"Error handling message: {e}")

    async def start_server(self, host='localhost', port=8765):
        server = await websockets.serve(
            self.handle_connection,
            host,
            port
        )
        print(f"Server started on {host}:{port}")
        await server.wait_closed()

    async def handle_connection(self, websocket, path):
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"Connection error: {e}")

# Example usage
async def main():
    server = MMOGameServer()
    
    # Create some test items and players
    await server.register_player("player1", "Alice")
    await server.register_player("player2", "Bob")
    
    await server.create_item("sword_1", "Iron Sword", "weapon", 100, "player1")
    await server.create_item("potion_1", "Health Potion", "consumable", 50, "player1")
    await server.create_item("shield_1", "Wooden Shield", "armor", 75, "player2")
    
    # Start server
    await server.start_server()

# Run with: asyncio.run(main())